  1→/**
  2→ * ExceptionRequestDetailModal Component
  3→ *
  4→ * Modal for viewing detailed information about an exception request
  5→ *
  6→ * Features:
  7→ * - Vulnerability details (CVE, severity, asset, days open, products)
  8→ * - Request details (scope, reason, expiration date)
  9→ * - Status information (current status, reviewer, review comments)
 10→ * - Auto-approval indicator
 11→ * - Cancel action for pending requests (owner only)
 12→ *
 13→ * Feature: 031-vuln-exception-approval
 14→ * User Story 1: Regular User Requests Exception (P1)
 15→ * Reference: spec.md FR-017
 16→ */
 17→
 18→import React, { useState, useEffect } from 'react';
 19→import { getRequestById, cancelRequest, type VulnerabilityExceptionRequestDto } from '../services/exceptionRequestService';
 20→import ExceptionStatusBadge from './ExceptionStatusBadge';
 21→
 22→interface ExceptionRequestDetailModalProps {
 23→    isOpen: boolean;
 24→    requestId: number;
 25→    onClose: () => void;
 26→    onUpdate?: () => void; // Optional callback after cancel
 27→}
 28→
 29→const ExceptionRequestDetailModal: React.FC<ExceptionRequestDetailModalProps> = ({
 30→    isOpen,
 31→    requestId,
 32→    onClose,
 33→    onUpdate
 34→}) => {
 35→    const [request, setRequest] = useState<VulnerabilityExceptionRequestDto | null>(null);
 36→    const [loading, setLoading] = useState(true);
 37→    const [error, setError] = useState<string | null>(null);
 38→    const [cancelling, setCancelling] = useState(false);
 39→
 40→    useEffect(() => {
 41→        if (isOpen) {
 42→            fetchRequestDetails();
 43→        }
 44→    }, [isOpen, requestId]);
 45→
 46→    const fetchRequestDetails = async () => {
 47→        try {
 48→            setLoading(true);
 49→            setError(null);
 50→            const data = await getRequestById(requestId);
 51→            setRequest(data);
 52→        } catch (err) {
 53→            const errorMessage = err instanceof Error ? err.message : 'Failed to load request details';
 54→            setError(errorMessage);
 55→        } finally {
 56→            setLoading(false);
 57→        }
 58→    };
 59→
 60→    const handleCancel = async () => {
 61→        if (!confirm('Are you sure you want to cancel this exception request?')) {
 62→            return;
 63→        }
 64→
 65→        try {
 66→            setCancelling(true);
 67→            await cancelRequest(requestId);
 68→
 69→            // Notify parent and close
 70→            if (onUpdate) {
 71→                onUpdate();
 72→            }
 73→            onClose();
 74→        } catch (err) {
 75→            const errorMessage = err instanceof Error ? err.message : 'Failed to cancel request';
 76→            setError(errorMessage);
 77→        } finally {
 78→            setCancelling(false);
 79→        }
 80→    };
 81→
 82→    // Handle keyboard navigation (Escape to close)
 83→    useEffect(() => {
 84→        if (!isOpen) return;
 85→
 86→        function handleKeyDown(e: KeyboardEvent) {
 87→            if (e.key === 'Escape' && !cancelling) {
 88→                onClose();
 89→            }
 90→        }
 91→
 92→        document.addEventListener('keydown', handleKeyDown);
 93→        return () => document.removeEventListener('keydown', handleKeyDown);
 94→    }, [isOpen, cancelling]);
 95→
 96→    // Don't render if not open
 97→    if (!isOpen) {
 98→        return null;
 99→    }
100→
101→    return (
102→        <>
103→            {/* Backdrop */}
104→            <div
105→                className="modal-backdrop fade show"
106→                onClick={onClose}
107→                style={{ zIndex: 1040 }}
108→            ></div>
109→
110→            {/* Modal */}
111→            <div
112→                className="modal fade show d-block"
113→                tabIndex={-1}
114→                role="dialog"
115→                style={{ zIndex: 1050 }}
116→                aria-labelledby="exceptionRequestDetailModalLabel"
117→                aria-modal="true"
118→            >
119→                <div className="modal-dialog modal-dialog-centered modal-lg">
120→                    <div className="modal-content">
121→                        {/* Header */}
122→                        <div className="modal-header">
123→                            <h5 className="modal-title" id="exceptionRequestDetailModalLabel">
124→                                Exception Request Details
125→                            </h5>
126→                            <button
127→                                type="button"
128→                                className="btn-close"
129→                                aria-label="Close"
130→                                onClick={onClose}
131→                                disabled={cancelling}
132→                            ></button>
133→                        </div>
134→
135→                        {/* Body */}
136→                        <div className="modal-body">
137→                            {loading && (
138→                                <div className="d-flex justify-content-center p-5">
139→                                    <div className="spinner-border" role="status">
140→                                        <span className="visually-hidden">Loading...</span>
141→                                    </div>
142→                                </div>
143→                            )}
144→
145→                            {error && (
146→                                <div className="alert alert-danger" role="alert">
147→                                    <i className="bi bi-exclamation-triangle me-2"></i>
148→                                    {error}
149→                                </div>
150→                            )}
151→
152→                            {request && !loading && (
153→                                <>
154→                                    {/* Status Section */}
155→                                    <div className="mb-4">
156→                                        <h6 className="text-muted mb-2">Current Status</h6>
157→                                        <div className="d-flex align-items-center">
158→                                            <ExceptionStatusBadge status={request.status} autoApproved={request.autoApproved} className="fs-6" />
159→                                        </div>
160→                                    </div>
161→
162→                                    {/* Auto-Approval Info Alert */}
163→                                    {request.autoApproved && (
164→                                        <div className="alert alert-info mb-4">
165→                                            <i className="bi bi-info-circle me-2"></i>
166→                                            <strong>Auto-Approved:</strong> This request was automatically approved because you have ADMIN or SECCHAMPION role.
167→                                        </div>
168→                                    )}
169→
170→                                    {/* Vulnerability Information */}
171→                                    <div className="mb-4">
172→                                        <h6 className="text-muted mb-3">Vulnerability Information</h6>
173→                                        <div className="row">
174→                                            <div className="col-md-6 mb-2">
175→                                                <strong>CVE ID:</strong>
176→                                                <br />
177→                                                <code>{request.vulnerabilityCveId || 'Unknown'}</code>
178→                                            </div>
179→                                            <div className="col-md-6 mb-2">
180→                                                <strong>Asset:</strong>
181→                                                <br />
182→                                                {request.assetName}
183→                                                {request.assetIp && (
184→                                                    <span className="text-muted ms-2">({request.assetIp})</span>
185→                                                )}
186→                                            </div>
187→                                        </div>
188→                                    </div>
189→
190→                                    {/* Request Information */}
191→                                    <div className="mb-4">
192→                                        <h6 className="text-muted mb-3">Request Information</h6>
193→                                        <div className="row mb-3">
194→                                            <div className="col-md-6 mb-2">
195→                                                <strong>Scope:</strong>
196→                                                <br />
197→                                                {request.scope === 'SINGLE_VULNERABILITY' ? (
198→                                                    <span className="badge bg-info text-dark">
199→                                                        <i className="bi bi-bullseye me-1"></i>
200→                                                        Single Vulnerability
201→                                                    </span>
202→                                                ) : (
203→                                                    <span className="badge bg-primary">
204→                                                        <i className="bi bi-grid-3x3 me-1"></i>
205→                                                        CVE Pattern
206→                                                    </span>
207→                                                )}
208→                                            </div>
209→                                            <div className="col-md-6 mb-2">
210→                                                <strong>Expiration Date:</strong>
211→                                                <br />
212→                                                {new Date(request.expirationDate).toLocaleDateString()}
213→                                            </div>
214→                                            <div className="col-md-6 mb-2">
215→                                                <strong>Submitted:</strong>
216→                                                <br />
217→                                                {new Date(request.createdAt).toLocaleString()}
218→                                            </div>
219→                                            <div className="col-md-6 mb-2">
220→                                                <strong>Requested By:</strong>
221→                                                <br />
222→                                                {request.requestedByUsername}
223→                                            </div>
224→                                        </div>
225→                                        <div>
226→                                            <strong>Reason:</strong>
227→                                            <div className="border rounded p-3 mt-2 bg-light" style={{ whiteSpace: 'pre-wrap' }}>
228→                                                {request.reason}
229→                                            </div>
230→                                        </div>
231→                                    </div>
232→
233→                                    {/* Review Information (if reviewed) */}
234→                                    {(request.status === 'APPROVED' || request.status === 'REJECTED') && (
235→                                        <div className="mb-4">
236→                                            <h6 className="text-muted mb-3">Review Information</h6>
237→                                            <div className="row mb-3">
238→                                                <div className="col-md-6 mb-2">
239→                                                    <strong>Reviewed By:</strong>
240→                                                    <br />
241→                                                    {request.reviewedByUsername || 'Unknown'}
242→                                                </div>
243→                                                <div className="col-md-6 mb-2">
244→                                                    <strong>Review Date:</strong>
245→                                                    <br />
246→                                                    {request.reviewDate ? new Date(request.reviewDate).toLocaleString() : '-'}
247→                                                </div>
248→                                            </div>
249→                                            {request.reviewComment && (
250→                                                <div>
251→                                                    <strong>Review Comment:</strong>
252→                                                    <div className={`border rounded p-3 mt-2 ${request.status === 'APPROVED' ? 'bg-success-subtle' : 'bg-danger-subtle'}`} style={{ whiteSpace: 'pre-wrap' }}>
253→                                                        {request.reviewComment}
254→                                                    </div>
255→                                                </div>
256→                                            )}
257→                                        </div>
258→                                    )}
259→
260→                                    {/* Cancellation Information (if cancelled) */}
261→                                    {request.status === 'CANCELLED' && (
262→                                        <div className="alert alert-secondary">
263→                                            <i className="bi bi-info-circle me-2"></i>
264→                                            This request was cancelled on {request.updatedAt ? new Date(request.updatedAt).toLocaleString() : 'unknown date'}.
265→                                        </div>
266→                                    )}
267→
268→                                    {/* Expiration Information (if expired) */}
269→                                    {request.status === 'EXPIRED' && (
270→                                        <div className="alert alert-warning">
271→                                            <i className="bi bi-clock me-2"></i>
272→                                            This approved exception expired on {new Date(request.expirationDate).toLocaleDateString()}.
273→                                        </div>
274→                                    )}
275→                                </>
276→                            )}
277→                        </div>
278→
279→                        {/* Footer */}
280→                        <div className="modal-footer">
281→                            <button
282→                                type="button"
283→                                className="btn btn-secondary"
284→                                onClick={onClose}
285→                                disabled={cancelling}
286→                            >
287→                                Close
288→                            </button>
289→                            {request && (request.status === 'PENDING' || (request.status === 'APPROVED' && request.autoApproved)) && (
290→                                <button
291→                                    type="button"
292→                                    className="btn btn-danger"
293→                                    onClick={handleCancel}
294→                                    disabled={cancelling}
295→                                    title={request.status === 'APPROVED' ? 'Revoke auto-approved exception' : 'Cancel pending request'}
296→                                >
297→                                    {cancelling ? (
298→                                        <>
299→                                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
300→                                            Cancelling...
301→                                        </>
302→                                    ) : (
303→                                        <>
304→                                            <i className="bi bi-x-circle me-2"></i>
305→                                            {request.status === 'APPROVED' ? 'Revoke Exception' : 'Cancel Request'}
306→                                        </>
307→                                    )}
308→                                </button>
309→                            )}
310→                        </div>
311→                    </div>
312→                </div>
313→            </div>
314→        </>
315→    );
316→};
317→
318→export default React.memo(ExceptionRequestDetailModal);
