 83→ *
 84→ * @param dto Request data with vulnerability ID, scope, reason, and expiration date
 85→ * @returns Created exception request
 86→ * @throws Error on 400 (validation), 401 (unauthorized), 409 (duplicate), 500 (server error)
 87→ */
 88→export async function createRequest(dto: CreateExceptionRequestDto): Promise<VulnerabilityExceptionRequestDto> {
 89→  const response = await authenticatedPost('/api/vulnerability-exception-requests', dto);
 90→
 91→  if (response.ok) {
 92→    return await response.json();
 93→  }
 94→
 95→  // Handle error responses
 96→  if (response.status === 400) {
 97→    const error = await response.json();
 98→    throw new Error(error.error || 'Invalid request data. Check reason length (50-2048 chars) and expiration date (must be in future).');
 99→  }
100→
101→  if (response.status === 401) {
102→    throw new Error('Unauthorized. Please login again.');
103→  }
104→
105→  if (response.status === 404) {
106→    const error = await response.json();
107→    throw new Error(error.error || 'Vulnerability not found.');
108→  }
109→
110→  if (response.status === 409) {
111→    const error = await response.json();
112→    throw new Error(error.error || 'An active exception request already exists for this vulnerability.');
113→  }
114→
115→  if (response.status === 500) {
116→    const error = await response.json();
117→    throw new Error(error.error || 'Failed to create exception request.');
118→  }
119→
120→  throw new Error(`Failed to create exception request: ${response.status}`);
121→}
