 41→  assetIp: string | null;
 42→  requestedByUserId: number;
 43→  requestedByUsername: string;
 44→  scope: ExceptionScope;
 45→  reason: string;
 46→  expirationDate: string;
 47→  status: ExceptionRequestStatus;
