248→
249→  if (response.status === 403) {
250→    throw new Error('You do not have permission to cancel this request. Only the requester can cancel their own requests.');
251→  }
252→
253→  if (response.status === 404) {
254→    throw new Error('Exception request not found.');
255→  }
256→
257→  if (response.status === 500) {
258→    const error = await response.json();
259→    throw new Error(error.error || 'Failed to cancel exception request.');
