502→/**
503→ * Export filters for Excel export
504→ */
505→export interface ExportFilters {
506→  status?: ExceptionRequestStatus;
507→  dateRange?: string;
508→  requesterId?: number;
509→  reviewerId?: number;
510→}
511→
512→/**
513→ * Export exception requests to Excel (ADMIN/SECCHAMPION only)
514→ *
515→ * @param filters Optional filters (status, dateRange, requesterId, reviewerId)
516→ * @returns void - triggers browser download
517→ * @throws Error on 401 (unauthorized), 403 (forbidden), 500 (server error)
518→ */
519→export async function exportToExcel(filters?: ExportFilters): Promise<void> {
520→  const params = new URLSearchParams();
521→  if (filters?.status) {
522→    params.append('status', filters.status);
523→  }
524→  if (filters?.dateRange) {
525→    params.append('dateRange', filters.dateRange);
526→  }
527→  if (filters?.requesterId) {
528→    params.append('requesterId', filters.requesterId.toString());
529→  }
530→  if (filters?.reviewerId) {
531→    params.append('reviewerId', filters.reviewerId.toString());
532→  }
533→
534→  const url = `/api/vulnerability-exception-requests/export${params.toString() ? '?' + params.toString() : ''}`;
535→  const response = await authenticatedGet(url);
536→
537→  if (response.ok) {
538→    // Extract filename from Content-Disposition header if available
539→    const contentDisposition = response.headers.get('Content-Disposition');
540→    let filename = 'exception-requests.xlsx';
541→    if (contentDisposition) {
542→      const filenameMatch = contentDisposition.match(/filename="(.+)"/);
543→      if (filenameMatch) {
544→        filename = filenameMatch[1];
545→      }
546→    }
547→
548→    // Download the blob
549→    const blob = await response.blob();
550→    const downloadUrl = window.URL.createObjectURL(blob);
551→    const link = document.createElement('a');
552→    link.href = downloadUrl;
553→    link.download = filename;
554→    document.body.appendChild(link);
555→    link.click();
556→    document.body.removeChild(link);
557→    window.URL.revokeObjectURL(downloadUrl);
558→    return;
559→  }
560→
561→  // Handle error responses
562→  if (response.status === 401) {
563→    throw new Error('Unauthorized. Please login again.');
564→  }
565→
566→  if (response.status === 403) {
567→    throw new Error('Access denied. This feature requires ADMIN or SECCHAMPION role.');
568→  }
569→
570→  if (response.status === 500) {
571→    const error = await response.json();
572→    throw new Error(error.error || 'Failed to export exception requests.');
573→  }
574→
575→  throw new Error(`Failed to export exception requests: ${response.status}`);
576→}
